INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00462', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '下列「」中的語詞，何者不是傳說中的神馬或良駒？', '["「飛黃」騰達", "「騏驥」一躍，不能十步", "「赤兔」思念舊主，絕食而死", "「金烏」玉兔最無情，驅馳不暫停"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00463', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「八荒霍霍驚仰首，空中□□逐日走。拔山倒海事事終，不追白日非英雄！果然手捉黃金烏，問公此 樂胡為乎？如何口渴顏色槁，一枝杖作鄧林草？」□□中所詠神話英雄為：', '["夸父", "刑天", "精衛", "盤古"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00464', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '司馬遷《史記．太史公自序》中記錄一段他父親的〈論六家要旨〉：「□□使人精神專一，動合無形， 贍足萬物。其為術也，因陰陽之大順，采儒墨之善，撮名法之要，與時遷移，應物變化。立俗施事， 無所不宜； 指約而易操，事少而功多。」上文中□□應填入的學派是：', '["法家", "名家", "道家", "雜家"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00465', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「你一直說要求仙，求俠／是崑崙太遠了，就近向你的酒瓶／去尋找邋遢俠和糊塗仙嗎？／——啊呀 要小心，好險哪／超這種貨櫃車可不是兒戲／慢一點吧，慢一點，我求求你／這幾年交通意外的統計 ／不下於安史之亂的傷亡／這跑天下呀究竟不是天馬／跑高速公路也不是行空／速限哪，我的謫仙， 是九十公里／你怎麼開到一百四了？」上述詩句為作者想像與某位詩人同遊高速公路，這位詩人應是：', '["陶潛", "李白", "李賀", "杜牧"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00466', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「朱泙漫學屠龍於支離益，單千金之家。三年技成而無所用其巧。」上文所闡述學習之理應是：', '["勤學好問", "學而不厭", "學以致用", "勤學苦練"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00467', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '「守河防敵卒當先，將鎮中央馬兩邊。此日鴻溝分楚漢，英雄割據待他年。」 詩中所描述的是何種民俗遊藝？', '["兵棋", "圍棋", "麻將", "象棋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00468', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '禮起於何也？曰：人生而有欲，欲而不得，則不能無求。求而無度量分界，則不能不爭；爭則亂，亂 則窮。先王惡其亂也，故制禮義以分之，以養人之欲，給人之求。使欲必不窮乎物，物必不屈於欲。 兩者相持而長，是禮之所起也。（《荀子・禮論》）下列敘述何者符合文意？', '["社會秩序混亂根本原因是資源不足", "作者認為人有天生自我節制的良知", "「禮」的功能類似經濟學中所謂供需可透過分配達到平衡", "「禮」的生成類似經濟學所說「看不見的手」所創造的市場規則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00469', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '有五斗先生者，以酒德遊於人間，有以酒請者，無貴賤皆往，往必醉，醉則不擇地斯寢矣，醒則復起飲 也。常一飲五斗，因以為號焉。先生絶思慮，寡言語，不知天下之有仁義厚薄也。忽焉而去，倏然而來， 其動也天，其靜也地，故萬物不能縈心焉。嘗言曰：「天下大抵可見矣。生何足養，而嵇康著論；途何 為窮，而阮籍慟哭。故昏昏默默，聖人之所居也。」遂行其志，不知所如。（王績〈五斗先生傳〉） 下列選項，何者最適合用來形容五斗先生？', '["飯蔬飲水", "率性而為", "獨善其身", "縱情恣欲"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00470', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '承上題，「故昏昏默默，聖人之所居也」，「昏昏」之意與下列何者最為相近？', '["「昏昏」欲睡", "俗人昭昭，我獨「昏昏」", "霏霏野霧合，「昏昏」隴日沉", "鸞絃代雁曲如語，一醉「昏昏」天下迷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00471', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-110-01c5eaab', 'sub-aboriginal-57f41407-05', NULL, 'single_choice', '王戎喪兒萬子，山簡往省之，王悲不自勝，簡曰：「孩抱中物，何至於此？」王曰：「聖人忘情，最下 不及情；情之所鍾，正在我輩。」簡服其言，更為之慟。（《世說新語•傷逝》） 上文中的「我輩」具有何種特質？', '["以學聖人為人生目標", "具有社會地位與學識", "對所愛者有深刻感情", "會因年老而偏疼孩子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:17+00:00", "source_pdf_sha1": "e5bf3f0d4288", "answer_pdf_sha1": "38e0530a220d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
